class Solution:
    def countPartitions(self, nums, k):
        n = len(nums)
        total = sum(nums)
        count = 0
        for mask in range(1 << n):
            s = 0
            for i in range(n):
                if mask & (1 << i):
                    s += nums[i]
            if s >= k and (total - s) >= k:
                count += 1
        return count % 1000000007

