class Solution:
    def countPartitions(self, nums, k):
        MOD = 1000000007
        total = sum(nums)
        n = len(nums)
        if total < 2 * k:
            return 0
        dp = [0] * k
        dp[0] = 1
        for num in nums:
            if num >= k:
                continue
            for j in range(k - 1, num - 1, -1):
                dp[j] = (dp[j] + dp[j - num]) % MOD
        bad = sum(dp) % MOD
        ans = (pow(2, n, MOD) - 2 * bad) % MOD
        return ans % MOD

